import { describe, it, expect, vi, beforeEach } from 'vitest'
import { getArticleBySlug } from './article-repository'
import * as strapiClient from '../strapi/client'

vi.mock('../strapi/client')

describe('getArticleBySlug', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('returns article when found', async () => {
    const mockArticle = {
      id: 1,
      slug: 'test-article',
      title: 'Test Article',
    }

    vi.mocked(strapiClient.fetchArticles).mockResolvedValue([
      mockArticle,
    ])

