    vi.mocked(strapiClient.fetchArticles).mockResolvedValue([])

    const result = await getArticleBySlug('nonexistent')
    expect(result).toBeNull()
  })
})

// lib/validation/contact-schema.test.ts
import { describe, it, expect } from 'vitest'
import { contactFormSchema } from './contact-schema'

describe('contactFormSchema', () => {
  it('accepts valid data', () => {
    const valid = {
      name: 'John Doe',
      email: 'john@example.com',
      message: 'Hello, I need help with...',
      interests: ['Web Development'],
    }

    const result = contactFormSchema.safeParse(valid)
    expect(result.success).toBe(true)
  })

  it('rejects short names', () => {
    const invalid = {
      name: 'J',
      email: 'john@example.com',
      message: 'Hello, I need help with...',
      interests: ['Web Development'],
    }

    const result = contactFormSchema.safeParse(invalid)
    expect(result.success).toBe(false)
    expect(result.error?.issues[0].message).toContain('at least 2')
  })

  it('rejects invalid email', () => {
    const invalid = {
      name: 'John Doe',
      email: 'not-an-email',
      message: 'Hello',
      interests: ['Web Development'],
    }

    const result = contactFormSchema.safeParse(invalid)
    expect(result.success).toBe(false)
  })
})

// components/atoms/Button/Button.test.tsx
import { describe, it, expect, vi } from 'vitest'
import { render, screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { Button } from './Button'

describe('Button', () => {
  it('renders children', () => {
    render(<Button>Click me</Button>)
    expect(screen.getByText('Click me')).toBeInTheDocument()
  })

  it('calls onClick when clicked', async () => {
    const handleClick = vi.fn()
    const user = userEvent.setup()

    render(<Button onClick={handleClick}>Click me</Button>)
    await user.click(screen.getByText('Click me'))

    expect(handleClick).toHaveBeenCalledTimes(1)
  })

  it('is disabled when disabled prop is true', () => {
    render(<Button disabled>Click me</Button>)
    expect(screen.getByText('Click me')).toBeDisabled()
  })

  it('renders loading state', () => {
    render(<Button isLoading>Click me</Button>)
    expect(screen.getByRole('button')).toHaveAttribute('aria-busy', 'true')
  })
})

// components/organisms/ContactForm/ContactForm.test.tsx
import { describe, it, expect, vi } from 'vitest'
import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { ContactForm } from './ContactForm'

describe('ContactForm', () => {
  it('renders all fields', () => {
    render(<ContactForm />)

    expect(screen.getByLabelText(/name/i)).toBeInTheDocument()
    expect(screen.getByLabelText(/email/i)).toBeInTheDocument()
    expect(screen.getByLabelText(/message/i)).toBeInTheDocument()
  })

  it('shows validation errors on submit', async () => {
    const user = userEvent.setup()
    render(<ContactForm />)

    await user.click(screen.getByRole('button', { name: /submit/i }))

    await waitFor(() => {
      expect(screen.getByText(/name is required/i)).toBeInTheDocument()
    })
  })

  it('submits valid data', async () => {
    const handleSubmit = vi.fn()
    const user = userEvent.setup()

    render(<ContactForm onSubmit={handleSubmit} />)

    await user.type(screen.getByLabelText(/name/i), 'John Doe')
    await user.type(screen.getByLabelText(/email/i), 'john@example.com')
    await user.type(screen.getByLabelText(/message/i), 'Hello, I need help')

    await user.click(screen.getByRole('button', { name: /submit/i }))

    await waitFor(() => {
      expect(handleSubmit).toHaveBeenCalledWith(
        expect.objectContaining({
          name: 'John Doe',
          email: 'john@example.com',
        })
      )
    })
  })
})

