// app/api/contact/route.test.ts
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { POST } from './route'
import * as emailService from '@/lib/email/send'

vi.mock('@/lib/email/send')

describe('POST /api/contact', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('accepts valid contact form', async () => {
    vi.mocked(emailService.sendEmail).mockResolvedValue({ success: true })

    const formData = new FormData()
    formData.append('name', 'John Doe')
    formData.append('email', 'john@example.com')
    formData.append('message', 'Hello, I need help')

    const request = new Request('http://localhost:3000/api/contact', {
      method: 'POST',
      body: formData,
    })

    const response = await POST(request)
    const data = await response.json()

    expect(response.status).toBe(200)
    expect(data.success).toBe(true)
    expect(emailService.sendEmail).toHaveBeenCalledTimes(1)
  })

  it('rejects invalid email', async () => {
    const formData = new FormData()
    formData.append('name', 'John Doe')
    formData.append('email', 'invalid-email')
    formData.append('message', 'Hello')

    const request = new Request('http://localhost:3000/api/contact', {
      method: 'POST',
      body: formData,
    })

    const response = await POST(request)
    const data = await response.json()

    expect(response.status).toBe(400)
    expect(data.error).toContain('email')
    expect(emailService.sendEmail).not.toHaveBeenCalled()
  })

  it('handles email service failure', async () => {
    vi.mocked(emailService.sendEmail).mockRejectedValue(
      new Error('SMTP error')
    )

    const formData = new FormData()
    formData.append('name', 'John Doe')
    formData.append('email', 'john@example.com')
    formData.append('message', 'Hello')

    const request = new Request('http://localhost:3000/api/contact', {
      method: 'POST',
      body: formData,
    })

    const response = await POST(request)
    const data = await response.json()

    expect(response.status).toBe(500)
    expect(data.error).toBeDefined()
  })
})

